// items[0] = Gmail list response  ({messages: [{id, threadId}], resultSizeEstimate})
// items[1] = Open Tasks query response

const items = $input.all();
const gmailList = items[0].json;
const openTasks = items[1].json;

// Build set of Gmail message IDs already harvested
const existingMessageIds = new Set();
for (const page of (openTasks.results || [])) {
  const props = page.properties || {};
  const notes = ((props.Notes && props.Notes.rich_text) || []).map(t => t.plain_text || '').join('');
  const source = ((props.Source && props.Source.rich_text) || []).map(t => t.plain_text || '').join('');
  const combined = `${notes}\n${source}`;
  for (const m of combined.matchAll(/Gmail message ID: ([^\s\n]+)/g)) {
    existingMessageIds.add(m[1]);
  }
}

const messages = gmailList.messages || [];
const toProcess = [];
const skipped = [];
for (const m of messages) {
  if (existingMessageIds.has(m.id)) {
    skipped.push({ reason: 'already harvested', message_id: m.id });
    continue;
  }
  toProcess.push({ message_id: m.id, thread_id: m.threadId });
}

return { to_process: toProcess, skipped, skipped_count: skipped.length, to_process_count: toProcess.length, total_inbox: messages.length };

// Decode Gmail message into plain text + metadata; attach LLM prompt.

const message = $('Split messages').item.json;
const gm = $json || {};
const payload = gm.payload || {};
const headers = payload.headers || [];

function headerVal(name) {
  const h = headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

const subject = headerVal('Subject');
const from = headerVal('From');
const to = headerVal('To');
const cc = headerVal('Cc');
const date = headerVal('Date');
const listUnsub = headerVal('List-Unsubscribe');

// Walk parts to find text/plain or text/html
function findText(part) {
  if (!part) return '';
  if (part.mimeType === 'text/plain' && part.body && part.body.data) {
    return Buffer.from(part.body.data, 'base64').toString('utf-8');
  }
  if (part.parts) {
    for (const p of part.parts) {
      const t = findText(p);
      if (t) return t;
    }
  }
  // fallback to html if no plain
  if (part.mimeType === 'text/html' && part.body && part.body.data) {
    const html = Buffer.from(part.body.data, 'base64').toString('utf-8');
    // crude html-to-text
    return html.replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/\s+/g, ' ').trim();
  }
  return '';
}

let bodyText = findText(payload);
if (!bodyText) bodyText = gm.snippet || '';
bodyText = bodyText.slice(0, 20000);

// Build Gmail thread URL
const threadUrl = `https://mail.google.com/mail/u/0/#inbox/${message.thread_id}`;

// If it looks like a newsletter (has List-Unsubscribe), still classify but signal to LLM
const isLikelyAutomated = !!listUnsub;

const prompt = `You are extracting action items from an email.

From: ${from}
To: ${to}
Cc: ${cc}
Date: ${date}
Subject: ${subject}
List-Unsubscribe header present: ${isLikelyAutomated ? 'YES (likely automated/newsletter)' : 'no'}

Body:
${bodyText}

---

Determine whether this email contains action items requiring follow-through.

Skip (return empty action_items) if:
- The email is a newsletter, marketing, or automated notification
- The email is a calendar invite/decline/accept confirmation
- The email is a receipt or transactional confirmation
- The email is FYI/forwarded with no explicit ask
- The email is a no-reply automated alert

For actionable emails, extract every action item. For each:
- text: the action item, rewritten as a concise imperative (≤120 chars)
- owner: "Sales User" if Sales User is responsible. Otherwise the named person, or "Unassigned".
- due_date: ISO date YYYY-MM-DD if mentioned, else null
- context: one short phrase (≤80 chars) explaining what the AI relates to

Owner attribution:
- If sender is asking Sales User to do X → owner = "Sales User"
- If Sales User (sender) is asking someone to do X → owner = that person
- If someone said they would do X for Sales User → owner = that person

Project classification (pick ONE):
- Example Company Pipeline
- Example Company Business Development
- Corporate Development
- Content
- Operations
- Personal
- Non-Sales Admin
- Other

Return ONLY JSON, no prose:
{
  "project": "<one>",
  "summary": "<one-sentence summary of email purpose, ≤180 chars>",
  "action_items": [
    {"text": "...", "owner": "Sales User", "due_date": null, "context": "..."}
  ]
}`;

return { message, subject, from, to, date, body_length: bodyText.length, thread_url: threadUrl, is_automated: isLikelyAutomated, prompt };

// Parse LLM, build Open Tasks payload.

const meta = $('Build prompt').item.json;
const message = meta.message;
const llm = $json || {};

let extracted = null;
let error = null;
try {
  const text = (llm.content || []).map(c => c.text || '').join('');
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON in response: ' + text.slice(0, 200));
  extracted = JSON.parse(m[0]);
} catch (e) {
  error = e.message;
}

if (error || !extracted) {
  return { skip: true, reason: error || 'parse failed', message_id: message.message_id, subject: meta.subject };
}

const ais = (extracted.action_items || []).filter(a => a && a.text && a.text.trim());
if (ais.length === 0) {
  return { skip: true, reason: 'no AIs extracted', message_id: message.message_id, subject: meta.subject, summary: extracted.summary };
}

const emailDate = (meta.date || '').slice(0, 30);
const ownerSet = [...new Set(ais.map(a => a.owner || 'Unassigned'))];
const titleBase = (((ais[0] || {}).text || '').trim() + (ais.length > 1 ? ' (+' + (ais.length - 1) + ' more)' : '')).slice(0, 190);

const notesLines = [];
notesLines.push(`Source URL: ${meta.thread_url}`);
notesLines.push(`Gmail message ID: ${message.message_id}`);
notesLines.push(`Gmail thread ID: ${message.thread_id}`);
notesLines.push(`From: ${meta.from || ''}`);
notesLines.push(`To: ${meta.to || ''}`);
notesLines.push(`Date: ${emailDate}`);
notesLines.push(`Summary: ${extracted.summary || ''}`);
notesLines.push('');
notesLines.push('Action items:');
for (const a of ais) {
  const due = a.due_date ? ` (due ${a.due_date})` : '';
  notesLines.push(`- [${a.owner || 'Unassigned'}] ${a.text}${due}${a.context ? ` — ${a.context}` : ''}`);
}
const notesText = notesLines.join('\n').slice(0, 1990);

const validProjects = new Set(['Example Company Pipeline','Example Company Business Development','Corporate Development','Content','Operations','Personal','Non-Sales Admin']);
const projectName = validProjects.has(extracted.project) ? extracted.project : null;

const properties = {
  Task: { title: [{ text: { content: titleBase } }] },
  Status: { status: { name: 'Not started' } },
  Source: { rich_text: [{ text: { content: `Email: ${meta.subject || ''}`.slice(0, 190) } }] },
  Notes: { rich_text: [{ text: { content: notesText } }] },
};
if (projectName) properties.Project = { select: { name: projectName } };

return {
  skip: false,
  message_id: message.message_id,
  subject: meta.subject,
  ai_count: ais.length,
  owners: ownerSet,
  notion_payload: {
    parent: { data_source_id: 'REPLACE_WITH_DATA_SOURCE_ID' },
    properties,
  },
  preview: { title: titleBase, notes: notesText.slice(0, 300) },
};

const out = [];
for (const item of $input.all()) {
  if (item.json && item.json.notion_payload && !item.json.skip) {
    out.push({ json: item.json });
  }
}
return out;

const created = $input.all().map(i => i.json);
const plan = $('Plan harvest').first().json;

const summary = {
  inbox_total: plan.total_inbox,
  to_process: plan.to_process_count,
  skipped_at_plan: plan.skipped_count,
  rows_created: created.length,
  generated_at: new Date().toISOString(),
};

return { summary, plan_skipped: plan.skipped, created };
